// The priority of zenoh messages.
type Priority int

const (
	PriorityRealTime        Priority = C.Z_PRIORITY_REAL_TIME        // Priority for ``RealTime`` messages.
	PriorityInteractiveHigh Priority = C.Z_PRIORITY_INTERACTIVE_HIGH // Highest priority for ``Interactive`` messages.
	PriorityInteractiveLow  Priority = C.Z_PRIORITY_INTERACTIVE_LOW  // Lowest priority for ``Interactive`` messages.
	PriorityDataHigh        Priority = C.Z_PRIORITY_DATA_HIGH        // Highest priority for ``Data`` messages.
	PriorityData            Priority = C.Z_PRIORITY_DATA             // Default priority for ``Data`` messages.
	PriorityDataLow         Priority = C.Z_PRIORITY_DATA_LOW         // Lowest priority for ``Data`` messages.
	PriorityBackground      Priority = C.Z_PRIORITY_BACKGROUND       // Priority for ``Background traffic`` messages.
	PriorityDefault         Priority = C.CGO_Z_PRIORITY_DEFAULT
)

// The congestion control policy to apply when routing zenoh messages.
type CongestionControl int

const (
	CongestionControlBlock   CongestionControl = C.Z_CONGESTION_CONTROL_BLOCK // Messages are not dropped in case of congestion.
	CongestionControlDrop    CongestionControl = C.Z_CONGESTION_CONTROL_DROP  // Messages are dropped in case of congestion.
	CongestionControlDefault CongestionControl = C.CGO_Z_CONGESTION_CONTROL_DEFAULT
)

// A Zenoh ID. In general, valid Zenoh IDs are LSB-first 128bit unsigned and non-zero integers.
type Id struct {
	id C.z_id_t
}

// Formats the `Id` into 16-digit hex string (LSB-first order).
func (id Id) String() string {
	var s C.z_owned_string_t
	C.z_id_to_string(&id.id, &s)
	loanedString := C.z_string_loan(&s)
	out := C.GoStringN(C.z_string_data(loanedString), C.int(C.z_string_len(loanedString)))
	C.zc_cgo_string_drop(&s)
	return out
}

// Return the byte sequence of the “Id“.
func (id Id) Bytes() []byte {
	return C.GoBytes(unsafe.Pointer(&id.id.id[0]), 16)
}

func newIdFromCPtr(cId *C.z_id_t) Id {
	return Id{id: *cId}
}

//go:linkname newIdFromUnsafeCPtr
func newIdFromUnsafeCPtr(cId unsafe.Pointer) Id {
	return newIdFromCPtr((*C.z_id_t)(cId))
}

// A [Zenoh timestamp]. It consists of a time generated by a Hybrid Logical Clock (HLC) in NPT64 format and a unique zenoh identifier.
//
// [Zenoh timestamp]: https://zenoh.io/docs/manual/abstractions/#timestamp
type TimeStamp struct {
	timestamp C.z_timestamp_t
}

func timeStampToC(timestamp TimeStamp, cTimestamp *C.z_timestamp_t) {
	*cTimestamp = timestamp.timestamp
}

//go:linkname timeStampToUnsafeC
func timeStampToUnsafeC(timestamp TimeStamp, cTimestamp unsafe.Pointer) {
	timeStampToC(timestamp, (*C.z_timestamp_t)(cTimestamp))
}

// Create uhlc timestamp from session id.
func (session *Session) NewTimestamp() TimeStamp {
	var ts TimeStamp
	C.z_timestamp_new(&ts.timestamp, C.z_session_loan(session.session))
	return ts
}

// Get the NTP64 time part of the timestamp.
func (timestamp TimeStamp) Time() uint64 {
	return uint64(C.z_timestamp_ntp64_time(&timestamp.timestamp))
}

// Get the [Id] associated with the timestamp.
func (timestamp TimeStamp) Id() Id {
	return Id{id: C.z_timestamp_id(&timestamp.timestamp)}
}

type qos struct {
	priority          Priority
	congestionControl CongestionControl
	isExpress         bool
}

// Warning: This API has been marked as unstable: it works as advertised, but it may be changed in a future release.
//
// The publisher reliability.
// Currently `reliability` does not trigger any data retransmission on the wire. It is rather used as a marker on the wire and it may be used to select the best link available (e.g. TCP for reliable data and UDP for best effort data).
type Reliability int

const (
	ReliabilityBestEffort Reliability = C.Z_RELIABILITY_BEST_EFFORT // Defines reliability as ``best effort``.
	ReliabilityReliable   Reliability = C.Z_RELIABILITY_RELIABLE    // Defines reliability as ``reliable``.
	ReliabilityDefault    Reliability = C.CGO_Z_RELIABILITY_DEFAULT
)

// The locality of data to be received or targeted.
type Locality int

const (
	LocalityAny          Locality    = C.Z_LOCALITY_ANY           // Any.
	LocalitySessionLocal Locality    = C.Z_LOCALITY_SESSION_LOCAL // Only from/to local sessions.
	LocalityRemote       Reliability = C.Z_LOCALITY_REMOTE        // Only from/to remote sessions.
	LocalityDefault      Locality    = LocalityAny
)

// The kinds of accepted query replies.
//
// The queryable may serve glob-like key expressions.
// E.g., the queryable may be declared with the key expression `foo/*`.
// At the same time, it may send replies with more specific key expressions, e.g., `foo/bar` or `foo/baz`.
// This may cause a situation when the queryable receives a query with the key expression `foo/bar`
// and replies to it with the key expression `foo/baz`.
// By default, this behavior is not allowed. Calling `z_query_reply` value on a query for `foo/bar` with key expression
// `foo/baz` will result in an error on the sending side. But if the query is sent with the `accept_replies` flag set
// to [ReplyKeyexpr.ReplyKeyexprAny] in either [GetOptions] or [QuerierOptions], then the reply with a
// disjoint key expression will be accepted for this query.
//
// The queryable may check wether disjoint replies are allowed for a query with [Query.AcceptsReplies] function.
type ReplyKeyexpr int

const (
	ReplyKeyexprAny           ReplyKeyexpr = C.Z_REPLY_KEYEXPR_ANY            // Replies with any key expression.
	ReplyKeyexprMatchingQuery ReplyKeyexpr = C.Z_REPLY_KEYEXPR_MATCHING_QUERY // Only replies with key expressions matching the query key expression.
	ReplyKeyexprDefault       ReplyKeyexpr = ReplyKeyexprMatchingQuery
)

// Warning: This API has been marked as unstable: it works as advertised, but it may be changed in a future release.
//
// A Zenoh entity global id. Identifies a Zenoh entity (publisher, subscriber, queryable, etc.) uniquely in the system.
type EntityGlobalId struct {
	id C.z_entity_global_id_t
}

// Warning: This API has been marked as unstable: it works as advertised, but it may be changed in a future release.
//
// Returns the Zenoh ID (session ID) part of the entity global id.
func (eid EntityGlobalId) ZId() Id {
	return Id{id: C.z_entity_global_id_zid(&eid.id)}
}

// Warning: This API has been marked as unstable: it works as advertised, but it may be changed in a future release.
//
// Returns the entity ID part of the entity global id (unique within a session).
func (eid EntityGlobalId) EntityId() uint32 {
	return uint32(C.z_entity_global_id_eid(&eid.id))
}

func newEntityGlobalIdFromC(id C.z_entity_global_id_t) EntityGlobalId {
	return EntityGlobalId{id: id}
}

//go:linkname newEntityGlobalIdFromUnsafeCPtr
func newEntityGlobalIdFromUnsafeCPtr(cId unsafe.Pointer) EntityGlobalId {
	return newEntityGlobalIdFromC(*(*C.z_entity_global_id_t)(cId))
}
